INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '木马 | 单; CDNA 他们的码片序列分别为s1 (-1-1-1+1+1-1+1+1) ,s2 (-1-1+1-1+1+1+1-1) ，s3 (-1+1-1+1+1+1-1-1) ，s4 (-1+1-1-1-1-1+1-1) 。 接收到码片序列为 (-1 +1 -3 +1 -1 -3 +1 +1) ，则没有发送数据的终端是 (14) 。 cst s1的正交结果: 1，s2的正交结果: -1，s3正交结果: 0，s4 的内积结果: 1。 注: 正交结果是1表示收到数据是1，正交结果是-1表示收到数据0，正交结果是0，表示没有发送数据。', '["D. 重放", "A. s4", "B. s3", "D. s2"]', '', '', 2, '2024年综合知识', '2024,综合知识', 2024);
